# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

public async Task<bool> PurchaseTicketsAsync(int eventId, int userId, int quantity)
{
    var retryCount = 0;
    var maxRetries = 3;
    
    while (retryCount < maxRetries)
    {
        try
        {
            using var context = new EventBookingContext();
            
            var ticketPrice = await context.Events
                .Where(e => e.Id == eventId)
                .Select(e => e.TicketPrice)
                .FirstOrDefaultAsync();
            
            if (ticketPrice == 0)
                return false;
            
            var availableSeats = await context.EventSeats
                .Where(es => es.EventId == eventId && es.IsAvailable)
                .CountAsync();
            
            if (availableSeats < quantity)
                return false;
            
            var transaction = await context.Database.BeginTransactionAsync();
            
            try
            {
                var seats = await context.EventSeats
                    .Where(es => es.EventId == eventId && es.IsAvailable)
                    .Take(quantity)
                    .ToListAsync();
                
                if (seats.Count != quantity)
                {
                    await transaction.RollbackAsync();
                    return false;
                }
                
                foreach (var seat in seats)
                {
                    seat.IsAvailable = false;
                    seat.UserId = userId;
                    seat.PurchaseDate = DateTime.UtcNow;
                }
                
                var purchase = new Purchase
                {
                    EventId = eventId,
                    UserId = userId,
                    Quantity = quantity,
                    TotalAmount = quantity * ticketPrice,
                    PurchaseDate = DateTime.UtcNow
                };
                
                context.Purchases.Add(purchase);
                await context.SaveChangesAsync();
                await transaction.CommitAsync();
                
                return true;
            }
            catch
            {
                await transaction.RollbackAsync();
                throw;
            }
        }
        catch (DbUpdateConcurrencyException)
        {
            retryCount++;
            await Task.Delay(TimeSpan.FromMilliseconds(100 * Math.Pow(2, retryCount)));
        }
        catch
        {
            return false;
        }
    }
    
    return false;
}